    const x1 = cx + hw * grow + shearX * 0.55;
    const y1 = cy - hh * (0.96 + (1 - lk) * 0.04);
    const x2 = cx + hw * grow - shearX * 0.45;
    const y2 = cy + hh * grow;
    const x3 = cx - hw * grow - shearX * 0.55;
    const y3 = cy + hh * (0.96 + (1 - lk) * 0.04);
