      const ox = Math.sin(opts.t * 0.0010 + mx * 7.0 + my * 3.0 + copy * 1.7) * off * dir;
      const oy = Math.cos(opts.t * 0.0009 + mx * 5.0 - my * 6.0 + copy * 1.3) * off * 0.85 * dir;
